import { describe, expect, it } from 'vitest';
import { deblurAnyImage } from '../src/deblur-any-image';
import {
  applyInvisibleWatermarkToPlane,
  floatPlaneToUint8Clamped,
  watermarkResidualCorrelation,
} from '../src/invisible-watermark';

describe('invisible watermark', () => {
  it('embeds deterministically with stable provenance id', () => {
    const width = 32;
    const height = 32;
    const plane = new Float32Array(width * height).fill(0.45);
    const options = {
      enabled: true,
      seed: 'stable-seed',
      payload: 'demo',
      strength: 0.02,
    } as const;

    const a = applyInvisibleWatermarkToPlane({
      plane,
      width,
      height,
      channels: 1,
      options,
    });
    const b = applyInvisibleWatermarkToPlane({
      plane,
      width,
      height,
      channels: 1,
      options,
    });
    expect(a.provenance?.id).toBe(b.provenance?.id);
    expect(a.provenance?.mode).toBe('luma_spread');
    expect(a.plane).toEqual(b.plane);
  });

  it('retains positive residual correlation after uint8 clamp roundtrip', () => {
    const width = 64;
    const height = 64;
    const baseline = new Float32Array(width * height * 3).fill(0.4);
    const options = {
      enabled: true,
      seed: 'corr-seed',
      payload: 'corr',
      strength: 0.018,
    } as const;
    const marked = applyInvisibleWatermarkToPlane({
      plane: baseline,
      width,
      height,
      channels: 3,
      options,
    }).plane;
    const markedU8 = floatPlaneToUint8Clamped(marked);
    const markedRoundtrip = new Float32Array(markedU8.length);
    for (let i = 0; i < markedU8.length; i++) {
      markedRoundtrip[i] = markedU8[i]! / 255;
    }
    const corr = watermarkResidualCorrelation({
      baseline,
      marked: markedRoundtrip,
      width,
      height,
      channels: 3,
      options,
    });
    expect(corr).toBeGreaterThan(0.2);
  });

  it('threads watermark options through deblurAnyImage result', async () => {
    const width = 24;
    const height = 24;
    const input = new Float32Array(width * height);
    for (let i = 0; i < input.length; i++) input[i] = 0.2 + (i % 11) * 0.01;
    const result = await deblurAnyImage(
      { data: input, width, height, channels: 1 },
      {
        sigma: 1.2,
        method: 'wiener',
        invisibleWatermark: {
          enabled: true,
          seed: 'deblur-seed',
          payload: 'deblur',
          strength: 0.012,
        },
      },
    );
    expect(result.invisibleWatermark?.id.length).toBeGreaterThan(0);
    expect(result.invisibleWatermark?.seedDigest.length).toBeGreaterThan(0);
  });
});
